import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import { ArrowLeft, Save, MapPin } from 'lucide-react';

const AddVendor = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    aadhaar: '',
    category: 'VEGETABLE',
    latitude: '',
    longitude: '',
    address: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const getCurrentLocation = () => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition((position) => {
        setFormData({
          ...formData,
          latitude: position.coords.latitude,
          longitude: position.coords.longitude
        });
      }, (err) => {
        alert("Unable to retrieve location: " + err.message);
      });
    } else {
      alert("Geolocation is not supported by your browser");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post('http://localhost:8080/api/vendors', {
        ...formData,
        latitude: parseFloat(formData.latitude),
        longitude: parseFloat(formData.longitude)
      });
      alert('Vendor registered successfully! Waiting for approval.');
      navigate('/vendors');
    } catch (err) {
      alert('Registration failed: ' + (err.response?.data?.message || err.message));
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="flex items-center gap-4">
        <button onClick={() => navigate('/vendors')} className="p-2 hover:bg-gray-200 rounded-full transition">
          <ArrowLeft size={20} />
        </button>
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Register New Vendor</h1>
          <p className="text-gray-500 text-sm">Add a new street vendor to the SMC system</p>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-md p-8 space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-600">Full Name</label>
            <input name="name" required value={formData.name} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="Vendor's full name" />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-600">Phone Number</label>
            <input name="phone" required value={formData.phone} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="10-digit mobile number" />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-600">Aadhaar Number (Last 4 digits)</label>
            <input name="aadhaar" required value={formData.aadhaar} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="XXXX-XXXX-XXXX" />
          </div>
          <div className="space-y-1">
            <label className="text-sm font-semibold text-gray-600">Vending Category</label>
            <select name="category" value={formData.category} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue">
              <option value="VEGETABLE">Vegetables</option>
              <option value="FRUIT">Fruits</option>
              <option value="FOOD">Fast Food / Snacks</option>
              <option value="TEA">Tea / Coffee</option>
              <option value="PAN_SHOP">Pan Shop</option>
              <option value="OTHER">Other</option>
            </select>
          </div>
        </div>

        <div className="border-t pt-6">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-bold text-gray-700 flex items-center gap-2">
              <MapPin size={18} className="text-smc-blue" /> Vending Location
            </h3>
            <button type="button" onClick={getCurrentLocation} className="text-smc-blue text-sm font-semibold hover:underline">
              Use Current GPS
            </button>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Latitude</label>
              <input name="latitude" required type="number" step="any" value={formData.latitude} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="0.000000" />
            </div>
            <div className="space-y-1">
              <label className="text-sm font-semibold text-gray-600">Longitude</label>
              <input name="longitude" required type="number" step="any" value={formData.longitude} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="0.000000" />
            </div>
            <div className="md:col-span-2 space-y-1">
              <label className="text-sm font-semibold text-gray-600">Specific Address / Landmark</label>
              <input name="address" value={formData.address} onChange={handleChange} className="w-full px-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-smc-blue" placeholder="e.g. Near Solapur Railway Station, Platform 1 exit" />
            </div>
          </div>
        </div>

        <div className="pt-4">
          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-smc-blue text-white py-3 rounded-lg font-bold hover:bg-blue-800 transition shadow-lg flex items-center justify-center gap-2 disabled:opacity-50"
          >
            <Save size={20} /> {loading ? 'Registering...' : 'REGISTER VENDOR'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default AddVendor;
